SELECT total_confirmed, total_deaths, total_recovered
FROM daily_updates
WHERE date = '2020-07-10';

SELECT date, total_confirmed, new_cases
FROM daily_updates
ORDER BY date DESC;

SELECT date, total_confirmed, total_deaths, total_recovered
FROM daily_updates
WHERE date = (SELECT MAX(date) FROM daily_updates);

SELECT COUNT(fips) AS high_incidence_regions
FROM covid_cases
WHERE date = '2020-07-09' AND incidence_rate > (SELECT AVG(incidence_rate) FROM covid_cases WHERE date = '2020-07-09');

SELECT date, total_confirmed
FROM daily_updates
ORDER BY date ASC;

SELECT confirmed
FROM covid_cases
WHERE fips = 0 AND date = '2020-07-09';

SELECT total_confirmed
FROM daily_updates
WHERE date = (SELECT MAX(date) FROM daily_updates);
